      const setFlowCategory = cat => { const defaults=timerDefaults(cat);state.builderPickCat=cat; state.builderCat=cat; state.builderName=`Ny ${flowLabel(cat)}-økt`; state.builder=[]; state.builderSearch=""; state.builderMuscle=""; state.builderEquipment=""; state.builderLevel=""; state.showRandomOptions=false; state.showBuilderFilters=false; state.commonSetCount=cat==="toying"?1:3; state.builderStep="exercises"; state.timerChoice=cat==="tabata"?"tabata":hasIntervalTimer(cat)?"interval":"none";if(hasIntervalTimer(cat)){state.globalWork=defaults.work;state.globalPause=defaults.pause;state.globalRounds=defaults.rounds;} save(); render(); };
      const startNewWorkoutFlow = () => { state.builder=[]; state.builderName="Ny økt"; state.builderSearch=""; state.builderMuscle=""; state.builderEquipment=""; state.builderLevel=""; state.showRandomOptions=false; state.showBuilderFilters=false; state.commonSetCount=3; state.builderStep="category"; state.builderMode="build"; state.tab="builder"; state.justAdded=""; state.editingProgramId=null; save(); render(); };
      const startSavedWorkout = p => {const cat=p.cat||"favoritt",defaults=timerDefaults(cat),ex=p.ex.map(e=>({...e,setCount:cat==="toying"?setCountOf(e):setCountOf(e)===1?3:setCountOf(e),targetReps:e.targetReps||e.reps||""})),choice=cat==="tabata"?"tabata":hasIntervalTimer(cat)?"interval":p.timerChoice||"none";state.pauseBetween=p.pauseBetween||0;state.globalWork=p.globalWork??ex[0]?.work??defaults.work;state.globalPause=p.globalPause??ex[0]?.pause??defaults.pause;state.globalRounds=p.globalRounds??ex[0]?.rounds??defaults.rounds;beginWorkout(p.name,cat,ex,choice);};
      const templateProgram = t => {const timerChoice=t.cat==="tabata"?"tabata":hasIntervalTimer(t.cat)?"interval":"none";const work=t.cat==="tabata"?20:t.cat==="toying"?45:40;const pause=t.cat==="tabata"?10:10;const rounds=t.cat==="tabata"?8:t.cat==="toying"?1:3;return {id:crypto.randomUUID(),sourceTemplateId:t.id,name:t.name,cat:t.cat,ex:t.ex.map(x=>({...entry(x[0],Number(x[1])||3,x[2]||""),work,pause,rounds})),timerChoice,pauseBetween:0,duration:t.duration,date:new Date().toISOString()};};
      const toggleTemplateFavorite = id => {state.favoriteTemplates=state.favoriteTemplates||[];state.savedPrograms=state.savedPrograms||[];const exists=state.favoriteTemplates.includes(id),t=templates.find(x=>x.id===id);if(exists){state.favoriteTemplates=state.favoriteTemplates.filter(x=>x!==id);state.savedPrograms=state.savedPrograms.filter(x=>x.sourceTemplateId!==id);}else if(t){state.favoriteTemplates.push(id);if(!state.savedPrograms.some(x=>x.sourceTemplateId===id))state.savedPrograms.unshift(templateProgram(t));}save();render();};
