      function start(name,cat,ex) { state.builderName=name; state.builder=ex; state.builderCat=cat; state.builderMode="active"; state.workoutStage="warmupPrompt"; state.activeIndex=0; state.swapIndex=null; state.intervalRun=null; state.guidedTimer=null; state.setRest={}; state.moreFocus=false; state.startedAt=Date.now(); state.energy=3; state.sleep=3; state.effort="middels"; state.pain=""; state.comment=""; state.completionMessage=""; state.tab="builder"; save(); render(); requestAnimationFrame(()=>document.querySelector(".focusScreen")?.scrollIntoView({block:"start"})); }
      function beginWorkout(name,cat,ex,timerChoice=state.timerChoice||"none") { state.builderName=name;state.builder=ex.map(e=>({...e}));state.builderCat=cat;state.builderPickCat=cat;state.timerChoice=cat==="tabata"?"tabata":hasIntervalTimer(cat)?"interval":timerChoice;state.tab="builder";if(usesIntervalTimer(cat,state.timerChoice)){state.builderStep="timer";state.builderMode="build";save();render();requestAnimationFrame(()=>document.querySelector(".commonTimerSettings")?.scrollIntoView({block:"start"}));return;}start(name,cat,state.builder); }
